const app = document.querySelector('#app');

const THRESHOLDS={rotateAlpha:38,tiltLeftGamma:-18,tiltRightGamma:18,liftBetaNegative:-18,liftBetaPositive:24,liftAccelerationZ:14};
const FISH_TYPES=[
 {name:'Sunny Orange Fish',class:'',rarity:.30},
 {name:'River Blue Fish',class:'blue',rarity:.22},
 {name:'Rose Petal Fish',class:'rose',rarity:.17},
 {name:'Jade Garden Fish',class:'jade',rarity:.14},
 {name:'Moonlight Violet Fish',class:'violet',rarity:.10},
 {name:'Golden Lotus Fish',class:'yellow',rarity:.06},
 {name:'Grand Lake Carp',class:'grand',rarity:.03,size:'large'}
];
const WAITING_LINES=['The lake is so peaceful today. Let’s see who comes to visit.','We can wait together. Little fish like a quiet moment.','The water is sparkling today. Something lovely may visit soon.'];
// Resident screens are always about enjoyment. Dimensions below are family-facing participation facts, never clinical interpretations.
const WELLNESS_DIMENSIONS={fishing:[{key:'movement',icon:'🖐',title:'Gentle movement',explanation:"Gentle arm movement, guided at Mary’s own pace"},{key:'focus',icon:'🌿',title:'Following the moment',explanation:'Followed Sunny’s calm movement cues'}],memory:[{key:'memory',icon:'🌸',title:'Remembering together',explanation:'Spent time matching familiar flowers'},{key:'focus',icon:'🌿',title:'Following the moment',explanation:'Stayed with a self-paced activity'}],conversation:[{key:'expression',icon:'💬',title:'Sharing memories',explanation:'Chose to share a personal memory'}],explore:[{key:'mood',icon:'☀',title:'Enjoying interests',explanation:'Chose an experience that felt inviting'}],relax:[{key:'mood',icon:'♫',title:'A peaceful pause',explanation:'Made time for a calming activity'}]};
const state = {
  view: 'welcome', previous: 'welcome', name: 'Mary', controller: false,
  session: { id:null, connected:false, error:null, attempts:0 }, controllerStep:'connect', tutorialStep:0, tutorialFeedback:null,
  motion: { enabled:false, permission:'unknown', baseline:null, lastEvent:0, samples:0 },
  fishing: { stage:'ready',caught:0,bait:3,baitActive:false,progress:0,started:null,activeFish:null,caughtFish:[],struggle:[],struggleStep:0,waitingLine:0,round:0 },
  memory: { open: [], matched: [], moves: 0, hints: 1, seconds: 0, locked: false },
  settings: { sound: true, motion: true, text: 'Comfortable' },
  ai:{intentTranscript:'',intentStatus:'idle',intentReply:'',intentError:'',chatMessages:[],chatBusy:false,chatTurns:0},
  moment:{step:0,started:null,paused:false,messages:[],busy:false,photo:null,photoBusy:false},
  momentHistory:[],
  metrics:{tutorialCorrect:0,tutorialWrong:0}, report:null, latestReport:null, profile:null, greeting:null, spokenKey:null
};
const query = new URLSearchParams(location.search);
const DEBUG=query.get('debug')==='1';
const API_BASE=location.protocol==='file:'?'http://localhost:4173':'';
const APP_PATH=location.pathname.includes('/moment/')?location.pathname.slice(0,location.pathname.indexOf('/moment/')+7):'';
if(query.has('session')){ state.controller=true; state.session.id=query.get('session').toUpperCase(); state.controllerStep='connect'; }

const flowers = [
  ['rose','rose'],['lavender','lavender'],['sunflower','sunflower'],['camellia','camellia'],
  ['hydrangea','hydrangea'],['rose','rose'],['sunflower','sunflower'],['camellia','camellia'],
  ['lavender','lavender'],['hydrangea','hydrangea'],['daisy','daisy'],['daisy','daisy']
].sort(() => .5 - Math.random());

function icon(name, cls=''){ return `<svg class="icon ${cls}" aria-hidden="true"><use href="assets/icons.svg#${name}"></use></svg>`; }
function escapeHtml(value=''){return String(value).replace(/[&<>"']/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[char]));}
const icons = { play:icon('flower'), explore:icon('spark'), talk:icon('flower'), relax:icon('star'), report:icon('flower'), settings:icon('star') };

function sun(stateName='idle', small=false){
  return `<div class="sunny ${stateName} ${small?'small':''}" aria-label="Sunny, your MOMENT companion"><img src="assets/art/sunny-companion.png" alt=""></div>`;
}

function logo(){ return `<button class="wordmark" data-go="welcome" aria-label="MOMENT home"><span>${sun('idle',true)}</span>MOMENT</button>`; }
function button(label, go, kind='primary', extra=''){ return `<button class="btn ${kind}" ${go?`data-go="${go}"`:''} ${extra}>${label}</button>`; }
function back(){ return `<button class="back" data-back aria-label="Go back">${icon('back')} <span>Back</span></button>`; }
function companion(message, mode='encouraging'){
  return `<div class="companion-row">${sun(mode)}<div class="speech">${message}<em>♡</em></div></div>`;
}
function nav(){
 return `<nav class="topnav">${logo()}<div class="navlinks">
  <button data-go="activities">Activities</button><button data-go="daily">Reports</button><button data-go="family">Family</button><button data-go="settings" aria-label="Settings">⚙</button>
 </div><button class="controller-chip" data-controller>${state.controller?'Large screen':'Phone controller'}</button></nav>`;
}
function shell(content, cls=''){ return `<main class="shell ${cls}">${content}</main>`; }
function todayLabel(){return new Intl.DateTimeFormat(undefined,{weekday:'long',day:'numeric',month:'long',year:'numeric'}).format(new Date())}

function welcome(){
 const remembered=state.greeting?.personalized,stateGreeting=remembered?state.greeting.greeting:`Hello, ${state.name}.`,stateSuggestion=remembered?state.greeting.suggestion:'I’m here to keep you company today.';
 return `<main class="home-dashboard">
  <nav class="dashboard-nav"><button class="dashboard-brand" data-go="welcome">${icon('flower')}<span><b>MOMENT</b><small>Your companion, every day.</small></span></button><div><button class="active" data-go="welcome">${icon('star')} Home</button><button data-go="activities">${icon('flower')} Activities</button><button data-go="daily">${icon('lotus')} Reports</button><button data-go="family">${icon('hand')} Family</button></div><button class="dashboard-controller" data-controller>${icon('hand')} Phone controller <i></i></button></nav>
  <section class="dashboard-stage"><div class="dashboard-copy"><h1>Good afternoon,<br>${state.name}</h1><p>Let’s make today a wonderful day. <span>♡</span></p></div>
   <div class="robot-speech ${remembered?'remembered':''}"><b>${escapeHtml(stateGreeting)}</b><span>${escapeHtml(stateSuggestion)} ♡</span></div>
   <div class="dashboard-cards">
    ${dashboardCard('fishing','Go Fishing','Enjoy a relaxing fishing adventure','pairing',icon('fish'))}
    ${dashboardCard('garden','Explore','Discover beautiful places and things','explore',icon('flower'))}
    ${dashboardCard('memories','Talk','Share memories and stories','talk',icon('hand'))}
    ${dashboardCard('music','Relax','Listen to music and relax your mind','relax',icon('sound'))}
   </div>
   <button class="dashboard-voice" data-go="listening"><span class="voice-mic">${icon('sound')}</span><span><b>You can say what you’d like</b><small>“I would like to go fishing”</small></span><i class="voice-wave"><b></b><b></b><b></b><b></b><b></b><b></b><b></b></i></button>
   <div class="dashboard-today"><div>${icon('lotus')}<span><b>Today</b><small>${todayLabel()}</small></span></div><hr><div>${icon('star')}<span><b>18°C</b><small>Sunny</small></span></div></div>
  </section>
 </main>`;
}
function dashboardCard(cls,title,sub,go,cardIcon){return `<button class="dashboard-card ${cls}" data-go="${go}"><span class="card-picture"><i></i></span><span class="card-round-icon">${cardIcon}</span><b>${title}</b><small>${sub}</small></button>`}
function activityButton(icon,title,sub,go){ return `<button class="activity-choice ${icon}" data-go="${go}"><span>${icons[icon]}</span><b>${title}</b><small>${sub}</small></button>`; }

function activities(){
 return `${nav()}${shell(`<div class="page-heading">${back()}<span><span class="eyebrow">CHOOSE A MOMENT</span><h1>What feels good today?</h1><p>There is no rush. Choose anything that sounds pleasant.</p></span></div>
 <div class="feature-grid">
  <article class="feature-card lake-card" data-go="pairing"><div class="mini-scene"><span class="mini-fish"><img src="assets/art/fish-orange.png" alt=""></span></div><div><span class="pill">A PEACEFUL MOMENT</span><h2>Sunny’s Peaceful Fishing</h2><p>Enjoy a peaceful day by the lake and see what little fish may come to visit.</p>${button('Visit the lake','pairing')}</div></article>
  <article class="feature-card flower-card" data-go="memory"><div class="flower-cluster">🌹 🪻<br>🌻 🌺</div><div><span class="pill">MEMORY & FOCUS</span><h2>Flower Memory Match</h2><p>Find beautiful flower pairs at your own pace.</p>${button('Match flowers →','memory','secondary')}</div></article>
 </div><h2 class="section-title">More ways to spend a moment</h2><div class="calm-grid">${activityButton('explore','Explore','Gardens, places and stories','explore')}${activityButton('talk','Talk','A conversation with Sunny','talk')}${activityButton('relax','Relax','Breathe, listen and unwind','relax')}</div>`, 'page')}`;
}

function activityHeader(title, subtitle, metric){ return `<header class="activity-header">${back()}<div><h1>${title}</h1><p>${subtitle}</p></div>${metric}</header>`; }

function fishing(){
 const f=state.fishing,fish=f.activeFish||FISH_TYPES[0],instruction={ready:'A lovely day for fishing — cast your line when you’re ready',waiting:'Let’s wait patiently for a little fish to visit',bite:fish.size==='large'?'A strong, friendly visitor! Lift with both hands, only as high as feels comfortable':'Something is nibbling! Lift your phone gently',biglift:'Lovely — hold your phone comfortably for a quiet moment',left:'Our visitor is swimming left — tilt gently',right:'Now it’s swimming right — follow it slowly',reeling:'Turn your phone gently to bring our visitor closer'}[f.stage];
 const caughtLine=fish.size==='large'?`A Grand Lake Carp!<br>What a magnificent, peaceful visitor.`:fish.name==='Golden Lotus Fish'?'A Golden Lotus Fish!<br>What a very special visitor.':`What a beautiful ${fish.name}!<br>You did a wonderful job.`,dialogue={ready:`Let’s go fishing together,<br>${state.name}.`,waiting:WAITING_LINES[f.waitingLine].replace('. ','.<br>'),bite:fish.size==='large'?'Oh! A bigger shadow is visiting.<br>Use both hands and stay comfortable.':'Oh! I think a little fish<br>is interested in our bait.',biglift:'Beautifully steady.<br>Sunny is holding the line with you.',left:'The fish is swimming left.<br>You’re doing wonderfully.',right:'Now gently to the right.<br>Perfect — you’ve got it.',reeling:'Turn slowly and gently.<br>It’s almost here!',caught:caughtLine}[f.stage];
 return shell(`${activityHeader('Sunny’s Peaceful Fishing','Enjoy a peaceful day by the lake and see what fish you can discover today.',`<div class="metric">${icon('lotus')}<small>Little visitors</small><b>${f.caught}</b></div>`)}
 <section class="fishing-scene ${fish.size==='large'?'grand-visitor':''} stage-${f.stage}" data-fish-scene><div class="ambient-light"></div><div class="cloud-soft cloud-a"></div><div class="cloud-soft cloud-b"></div><div class="water-sheen"></div><div class="butterfly"><i></i><i></i></div><div class="fish fish1 active-catch ${fish.class}"><img src="assets/art/fish-orange.png" alt="${fish.name}"></div><div class="fish fish2 blue"><img src="assets/art/fish-orange.png" alt=""></div><div class="fish fish3 yellow"><img src="assets/art/fish-orange.png" alt=""></div><span class="ripples ripple-one"></span><span class="ripples ripple-two"></span>${fish.size==='large'?'<span class="grand-ripple grand-ripple-a"></span><span class="grand-ripple grand-ripple-b"></span><div class="grand-shadow"></div>':''}<div class="dock"><i></i><i></i></div><div class="rod ${f.stage}"><i class="reel"></i><i class="handle"></i></div><svg class="line" viewBox="0 0 1000 600" preserveAspectRatio="none"><path d="M585,555 Q625,260 720,392"/></svg>
 ${companion(dialogue,f.stage==='caught'?'celebrating':f.stage==='waiting'?'speaking':'encouraging')}<div class="fishing-hud"><span>${icon('bait')}<small>Bait</small><b>${f.bait}</b></span><hr><span>${icon('star')}<small>Visitors</small><b>${f.caught}</b></span></div>
 ${f.caughtFish.length?`<div class="catch-shelf"><small>TODAY’S VISITORS</small>${f.caughtFish.map(item=>`<span class="${item.class}"><i></i>${item.name}</span>`).join('')}</div>`:''}
 ${f.stage==='caught'?`<div class="caught-actions"><p>${f.caught>=3?'That was a lovely visit. A little rest with Sunny might feel nice.':'Would you like to welcome another fish?'}</p>${button('Fish again',null,'primary','data-fish-again')}${button('Rest with Sunny',null,'secondary','data-rest-sunny')}</div>`:`<button class="instruction ${f.stage}" data-cast><span>${icon('hand')}</span><b>${instruction}</b></button>`}${f.progress?`<div class="reel-progress"><span style="width:${f.progress}%"></span></div>`:''}</section>
 <footer class="activity-footer">${button(`${icon('sound')} Music`,null,'purple','data-sound')}${button(`${icon('bait')} ${f.baitActive?'Bait is ready':'Use bait'}`,null,'green',`data-bait ${!f.bait||f.baitActive?'disabled':''}`)}${button(`${icon('exit')} Exit activity`,'activities','danger')}</footer>`, 'activity-shell fishing-shell');
}

function memory(){
 let cards=flowers.map((f,i)=>`<button class="memory-card ${state.memory.open.includes(i)||state.memory.matched.includes(i)?'flipped':''} ${state.memory.matched.includes(i)?'matched':''}" data-card="${i}" aria-label="${state.memory.open.includes(i)?f[0]:'Hidden flower card'}"><span class="card-inner"><span class="card-back">${icon('flower')}</span><span class="card-front"><b class="botanical ${f[1]}"><i></i><i></i><i></i><i></i><i></i><i></i></b><small>${f[0]}</small></span></span></button>`).join('');
 return shell(`${activityHeader('Flower Memory Match','Find all the matching flower pairs!',`<div class="metric">${icon('flower')}<small>Matches</small><b>${state.memory.matched.length/2} / 6</b></div>`)}
 <div class="memory-top">${companion(state.memory.matched.length?`Lovely work, ${state.name}!<br>Keep going.`:`Take your time, ${state.name}.<br>Every turn is a fresh start.`)}<div class="stat-row"><div>◉<small>Moves</small><b>${state.memory.moves}</b></div><div>◷<small>Time</small><b>${formatTime(state.memory.seconds)}</b></div><div>♧<small>Hints</small><b>${state.memory.hints}</b></div></div></div>
 <div class="memory-grid">${cards}</div><footer class="activity-footer">${button('↻  Restart',null,'green','data-restart')}${button('💡  Hint',null,'yellow','data-hint')}${button('↪  Exit activity','activities','danger')}</footer>`, 'activity-shell memory-shell');
}
function formatTime(n){ return `${String(Math.floor(n/60)).padStart(2,'0')}:${String(n%60).padStart(2,'0')}`; }

const experiences = {
 explore:{kicker:'A LITTLE DISCOVERY',title:'Let’s explore somewhere beautiful',body:'Take a gentle visit to gardens, coastlines and favourite places — with Sunny beside you.',cards:[['🌿','A walk through Monet’s garden'],['🏞️','The lakes of New Zealand'],['🐦','Meet the birds in your garden']]},
 talk:{kicker:'A CONVERSATION WITH SUNNY',title:'I’m here to listen',body:'Share a story, remember someone special, or simply talk about your day. This is your space.',cards:[['♡','A favourite family tradition'],['♫','Music that brings back memories'],['☕','The best part of today'],['▧','Tell me about this photo']]},
 relax:{kicker:'A PEACEFUL PAUSE',title:'Let’s make room to breathe',body:'Settle into a calming sound, a gentle breathing moment, or a quiet nature scene.',cards:[['🌧️','Soft rain on leaves'],['🌊','Waves along the shore'],['🎹','Quiet afternoon piano']]}
};
function experience(type){ const x=experiences[type]; return `${nav()}${shell(`<div class="page-heading experience-heading">${back()}<span><span class="eyebrow">${x.kicker}</span><h1>${x.title}</h1><p>${x.body}</p></span></div><div class="experience-hero ${type}">${companion(type==='talk'?`What’s on your mind, ${state.name}?`:`We can enjoy this together.`,'speaking')}<div class="orb">${icons[type]}</div></div><div class="story-cards ${x.cards.length===4?'four':''}">${x.cards.map((c,i)=>`<button data-story="${type}:${i}"><span>${c[0]}</span><b>${c[1]}</b><small>${i?'About 5 minutes':'Recommended for you'}</small><strong>Start this moment →</strong></button>`).join('')}</div>`, 'page experience-page')}`; }

function startMoment(type,index){
 state.momentSelection={type,index:+index};
 state.moment={step:0,started:Date.now(),paused:false,messages:[],busy:false,completed:false,photo:null,photoBusy:false};
 state.previous=type;
 state.view='momentPlaying';
 render();
}

function guidedMoment(){const {type,index}=state.momentSelection;const x=experiences[type],item=x.cards[index];const copy={explore:['Let’s look around together','Sunny will gently guide you through the scene. Pause whenever something catches your eye.'],talk:['This is your space','Share as much or as little as you like. Sunny will listen without rushing you.'],relax:['Settle in comfortably','Breathe naturally and let the sound create a quiet moment around you.']}[type];return shell(`<div class="guided-moment ${type}">${sun('speaking')}<span class="eyebrow">${type.toUpperCase()} WITH SUNNY</span><h1>${item[1]}</h1><p class="lead">${copy[0]}</p><div class="guided-panel"><div class="guided-visual">${icons[type]}<i></i><i></i><i></i></div><div><h2>${copy[1]}</h2><p>This moment is about five minutes. There is no rush and nothing you need to finish.</p><div class="guided-actions">${button('Begin this moment',null,'primary','data-begin-moment')}${button('Choose another',type,'secondary')}</div></div></div></div>`, 'state-shell guided-shell')}

const exploreMoments=[
 ['Notice the colours','What colours feel especially lovely to you?','Soft green','Warm flowers','Bright sky'],
 ['Listen to the place','Imagine the quiet sounds around you. What would you enjoy hearing?','Birdsong','Moving water','Leaves in the breeze'],
 ['Choose a favourite detail','Take your time and choose the part you would like to remember.','The garden path','The peaceful lake','A small visiting bird']
];
function momentPlaying(){const {type,index}=state.momentSelection,item=experiences[type].cards[index],m=state.moment;if(type==='explore'){const step=exploreMoments[m.step]||exploreMoments[2];return shell(`<div class="moment-live explore-live"><header>${logo()}<span class="moment-progress">${m.step+1} of 3</span></header><div class="moment-landscape scene-${index}"><span>${item[0]}</span><i></i><i></i><i></i></div><section>${sun('speaking')}<span class="eyebrow">LOOK AROUND WITH SUNNY</span><h1>${step[0]}</h1><p>${step[1]}</p><div class="moment-choices">${step.slice(2).map(choice=>`<button data-moment-choice="${escapeHtml(choice)}">${escapeHtml(choice)}</button>`).join('')}</div></section></div>`, 'state-shell moment-shell')}
 if(type==='talk'){const messages=m.messages.length?m.messages:[{role:'assistant',content:index===3?'Choose a photo when you feel ready. I’ll look gently and invite the story behind it.':`I’m right here, ${state.name}. What would you like to share?`}],photo=index===3?`<section class="photo-story"><label class="photo-picker"><input type="file" accept="image/jpeg,image/png,image/webp" data-photo-input><span>${m.photo?'Choose another photo':'Choose a photo'}</span><small>The photo stays in this moment and is not saved.</small></label>${m.photo?`<img src="${m.photo}" alt="Your selected photograph">`:''}${m.photoBusy?'<p>Sunny is looking carefully…</p>':''}</section>`:'';return shell(`<div class="moment-live talk-live"><header>${logo()}<span class="moment-progress">A quiet conversation</span></header>${sun('speaking')}<span class="eyebrow">TALK WITH SUNNY</span><h1>${item[1]}</h1>${photo}<div class="chat-thread">${messages.map(message=>`<div class="chat-message ${message.role}">${escapeHtml(message.content)}</div>`).join('')}${m.busy?'<div class="chat-message assistant typing">Sunny is listening carefully…</div>':''}</div><form class="chat-form" data-moment-chat><label for="momentChatInput">Share anything you like</label><div><input id="momentChatInput" name="message" placeholder="Type a thought or memory"><button class="btn primary" type="submit">Share</button><button class="btn ghost" type="button" data-moment-speech>Speak</button></div></form><div class="chat-choices"><button data-moment-prompt="family">A family memory</button><button data-moment-prompt="today">Something from today</button><button data-finish-moment>Finish gently</button></div></div>`, 'state-shell moment-shell')}
 return shell(`<div class="moment-live relax-live ${m.paused?'paused':''}"><header>${logo()}<span class="moment-progress">A peaceful pause</span></header>${sun('waiting')}<span class="eyebrow">RELAX WITH SUNNY</span><h1>${item[1]}</h1><div class="breathing-orb"><i></i><span>${m.paused?'Paused':'Breathe gently'}</span></div><p>${m.paused?'Take all the time you need.':'Breathe in comfortably, then let the breath leave slowly.'}</p><div class="guided-actions">${button(m.paused?'Continue':'Pause',null,'secondary','data-toggle-pause')}${button('Finish when ready',null,'primary','data-finish-moment')}</div></div>`, 'state-shell moment-shell')}
function momentComplete(){const {type,index}=state.momentSelection,item=experiences[type].cards[index],copy={explore:'You noticed something beautiful and made it your own.',talk:'Thank you for sharing a little of your day with Sunny.',relax:'You made a peaceful space for yourself today.'}[type];return shell(`<div class="moment-complete">${sun('celebrating')}<span class="eyebrow">A LOVELY MOMENT</span><h1>That was lovely, ${state.name}.</h1><p>${copy}</p><blockquote>“${escapeHtml(item[1])}”</blockquote><div class="guided-actions">${button('Choose another moment',type,'secondary')}${button('Return home','welcome','primary')}</div></div>`, 'state-shell')}
function completeMoment(){const {type,index}=state.momentSelection,item=experiences[type].cards[index];if(!state.moment.completed){state.moment.completed=true;const moment={type,title:item[1],durationSeconds:Math.max(1,Math.round((Date.now()-(state.moment.started||Date.now()))/1000)),shared:type==='talk'?state.moment.messages.find(message=>message.role==='user')?.content||'':''};state.momentHistory.unshift(moment);fetch(`${API_BASE}/api/ai/moment`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({activity:type,title:moment.title,durationSeconds:moment.durationSeconds,shared:moment.shared})}).catch(()=>{})}state.view='momentComplete';render()}

function listening(){const a=state.ai;return shell(`<div class="center-state voice-state">${logo()}<div class="listening-orb ${a.intentStatus==='listening'?'active':''}"><i></i><i></i><i></i><span>●</span></div><span class="eyebrow">${a.intentStatus==='listening'?'SUNNY IS LISTENING':'TALK WITH SUNNY'}</span><h1>${a.intentReply||'Tell me what sounds lovely today.'}</h1><p class="voice-transcript">${a.intentTranscript?`“${escapeHtml(a.intentTranscript)}”`:'You might say, “I’d like to spend some time by the lake.”'}</p>${a.intentError?`<p class="voice-error">${escapeHtml(a.intentError)}</p>`:''}${button(a.intentStatus==='listening'?'Listening…':'Speak to Sunny',null,'primary',`data-start-listening ${a.intentStatus==='listening'?'disabled':''}`)}<div class="voice-fallback">${button('Let’s go fishing','pairing','secondary')}${button('Explore','explore','ghost')}${button('Go back','welcome','ghost')}</div></div>`, 'state-shell'); }

function pairing(){
 const id=state.session.id||'••••'; const phoneBase=state.session.phoneBase||(location.protocol==='file:'?'http://localhost:4173':location.origin);const url=state.session.id?`${phoneBase}${APP_PATH}/index.html?session=${id}`:'';if(state.session.error)return shell(`<div class="pair-layout pair-fallback"><div>${logo()}<span class="eyebrow">PHONE CONNECTION</span><h1>Let’s reconnect<br>your phone.</h1><p>${escapeHtml(state.session.error)}</p><div class="guided-actions">${button('Try phone connection again',null,'primary','data-retry-pair')}${button('Start without a phone','fishingIntro','secondary')}${button('Choose another activity','activities','ghost')}</div><small>${location.hostname.endsWith('github.io')?'The GitHub Pages preview cannot run live pairing. Open the HTTPS server version for a real QR code.':'The server is available. A quick retry usually restores the QR code.'}</small></div><div class="pair-art">${sun('helping')}<h2>Sunny will create a fresh QR code for you.</h2></div></div>`, 'pair-shell');
 return shell(`<div class="pair-layout"><div>${logo()}<span class="eyebrow">A SIMPLE CONNECTION</span><h1>Let’s connect<br>your phone.</h1><p>Scan the code below with your phone’s camera. MOMENT will open and connect for you.</p><div class="pair-code">${id.split('').map(x=>`<span>${x}</span>`).join('')}</div><div class="status ${state.session.connected?'good connected-now':'good'}"><i></i>${state.session.connected?'Your phone is connected — continue on your phone.':'Waiting gently for your phone…'}</div></div><div class="pair-art qr-panel"><div id="qr" data-url="${url}"></div><p><b>Scan to begin</b><small>No typing needed</small></p>${sun(state.session.connected?'celebrating':'helping')}</div></div>`, 'pair-shell');
}

const tutorialSteps=[
  {title:'Lift your phone gently',body:'Just a small, comfortable lift.',motion:'↑',event:'lift'},
  {title:'Tilt a little to the left',body:'Perfect — only as far as feels comfortable.',motion:'←',event:'left'},
  {title:'Now tilt a little to the right',body:'That’s it. You’ve got it.',motion:'→',event:'right'},
  {title:'Turn your phone gently',body:'A small turning motion reels in the line.',motion:'↻',event:'rotate'}
];
function tutorial(){ const t=tutorialSteps[state.tutorialStep],fb=state.tutorialFeedback;const sunnyMessage=fb?.kind==='correct'?`Perfect, ${state.name}!<br>You’ve got it.`:fb?.kind==='wrong'?`Almost there.<br>Let’s try that movement again.`:state.tutorialStep?`You’re doing wonderfully,<br>${state.name}.`:`We’ll take it slowly, ${state.name}.`;return shell(`${activityHeader('Let’s practise together','Sunny will guide you one gentle movement at a time.',`<div class="metric">${icon('hand')}<small>Your progress</small><b>${state.tutorialStep+1} of 4</b></div>`)}<section class="tutorial-scene ${fb?`has-feedback ${fb.kind}`:''}">${companion(sunnyMessage,fb?.kind==='correct'?'celebrating':'encouraging')}<div class="tutorial-motion"><span>${fb?.kind==='correct'?'✓':fb?.kind==='wrong'?'↺':t.motion}</span><h1>${fb?.kind==='correct'?'That was just right!':fb?.kind==='wrong'?'Let’s try once more':t.title}</h1><p>${fb?.message||t.body}</p>${fb?.kind==='correct'?'':button(fb?.kind==='wrong'?'Try this movement again':'I’ve done this',null,'primary',`data-tutorial="${t.event}"`)}</div>${fb?`<div class="practice-feedback ${fb.kind}">${fb.kind==='correct'?icon('spark'):icon('hand')}<span><b>${fb.kind==='correct'?'Wonderful!':'Not quite yet'}</b><small>${fb.message}</small></span></div>`:''}</section>`, 'activity-shell tutorial-shell'); }

function fishingIntro(){return shell(`${activityHeader('Before we visit the lake','Sunny will show you everything first. There is no hurry.',`<div class="metric">${icon('spark')}<small>About</small><b>1 minute</b></div>`)}<section class="intro-scene">${companion(`Let me show you how<br>we’ll fish together, ${state.name}.`,'speaking')}<div class="intro-copy"><span class="eyebrow">SUNNY’S GENTLE GUIDE</span><h1>Fishing is simple<br>and peaceful.</h1><p>We will make one comfortable movement at a time.</p></div><div class="intro-steps"><article><span>1</span>${icon('hand')}<h2>Cast the line</h2><p>Tap once to send the line gently into the lake.</p></article><article><span>2</span><b class="step-arrow">↑</b><h2>Lift when it nibbles</h2><p>When Sunny notices a fish, lift your phone gently.</p></article><article><span>3</span><b class="step-arrow">↔</b><h2>Follow the fish</h2><p>Tilt left or right, only as far as feels comfortable.</p></article><article><span>4</span><b class="step-arrow">↻</b><h2>Reel it closer</h2><p>Turn your phone slowly to welcome the fish.</p></article></div><div class="intro-reassure">${icon('flower')} <span><b>You cannot do it wrong.</b> Sunny will wait and help whenever you need.</span></div><div class="intro-start">${button('Let’s practise together',null,'primary','data-demo-tutorial')}</div></section>`, 'activity-shell intro-shell')}

function conversation(){const messages=state.ai.chatMessages.length?state.ai.chatMessages:[{role:'assistant',content:'Did being by the lake bring back a happy memory?'}];return shell(`<div class="conversation-scene chat-scene">${sun(state.ai.chatBusy?'waiting':'speaking')}<span class="eyebrow">A MOMENT WITH SUNNY</span><h1>That was lovely, ${state.name}.</h1><div class="chat-thread" aria-live="polite">${messages.map(m=>`<div class="chat-message ${m.role}">${escapeHtml(m.content)}</div>`).join('')}${state.ai.chatBusy?'<div class="chat-message assistant typing">Sunny is thinking gently…</div>':''}</div><div class="chat-choices"><button data-memory="family">It reminded me of family</button><button data-memory="peaceful">I enjoyed the peaceful water</button></div><form class="chat-form" data-chat-form><label for="chatInput">Share a memory with Sunny</label><div><input id="chatInput" name="message" placeholder="Type anything you would like to share" autocomplete="off"><button class="btn primary" type="submit" ${state.ai.chatBusy?'disabled':''}>Share</button><button class="btn ghost" type="button" data-chat-speech>Speak</button></div></form>${state.ai.chatTurns?button('Finish this lovely moment',null,'secondary','data-finish-chat'):''}<p class="gentle-note">Share as much or as little as you like. Sunny will not rush you.</p></div>`, 'state-shell'); }

function reports(weekly=false){
 const latest=state.report||state.latestReport,facts=latest?.facts||{},hasFishing=Boolean(latest),history=state.momentHistory,hasAny=hasFishing||history.length>0,fishingMinutes=hasFishing?Math.max(1,Math.round((facts.durationSeconds||60)/60)):0,otherMinutes=Math.round(history.reduce((sum,item)=>sum+item.durationSeconds,0)/60),minutes=fishingMinutes+otherMinutes;
 const iconsByType={explore:'🌿',talk:'♡',relax:'♫'},timeline=[hasFishing?timelineItem('Today','Sunny’s Peaceful Fishing',`Welcomed ${facts.fishCaught??0} fish · ${fishingMinutes} minute${fishingMinutes===1?'':'s'}`,'🐟'):'',...history.map(item=>timelineItem('Today',item.title,`${item.type==='talk'&&item.shared?`Shared: “${escapeHtml(item.shared)}”`:`${Math.max(1,Math.round(item.durationSeconds/60))} gentle minute${item.durationSeconds>=90?'s':''}`}`,iconsByType[item.type]))].join('');
 const highlight=hasFishing?latest.family:history.length?`${state.name} chose ${history[0].title} and spent a gentle moment with Sunny.`:'No activities have been recorded yet. Choose a moment whenever it feels right.';
 return `${nav()}${shell(`<div class="page-heading compact"><div><span class="eyebrow">${weekly?'YOUR WEEK TOGETHER':'TODAY’S MOMENTS'}</span><h1>${hasAny?(weekly?'A gentle look at Mary’s week':'Mary shared some lovely moments'):'Your moments will appear here'}</h1><p>Shared with care — focused on enjoyment, interests and connection.</p></div><div class="segmented"><button data-go="daily" class="${!weekly?'active':''}">Daily</button><button data-go="weekly" class="${weekly?'active':''}">Weekly</button></div></div>
 <div class="report-highlight"><div><span class="date">${weekly?'THIS WEEK':'TODAY'}</span><h2>${hasAny?'Time chosen at Mary’s own pace':'Nothing needs to be completed.'}</h2><p>${escapeHtml(highlight)}</p><div class="tags">${[hasFishing?'Fishing':'',...new Set(history.map(item=>item.type))].filter(Boolean).map(tag=>`<span>${tag[0].toUpperCase()+tag.slice(1)}</span>`).join('')}</div></div>${sun(hasAny?'celebrating':'idle')}</div>
 <div class="report-grid"><article><span>☀</span><small>Fish welcomed</small><b>${facts.fishCaught??0}</b><p>A comfortable, self-paced activity</p></article><article><span>◷</span><small>Time together</small><b>${minutes} min</b><p>Across the moments Mary chose</p></article><article><span>♡</span><small>Shared memory</small><b>${facts.memory_note||history.some(item=>item.shared)?'Shared':'—'}</b><p>${escapeHtml(facts.memory_note||history.find(item=>item.shared)?.shared||'No memory was shared today.')}</p></article></div>
 <section class="timeline"><h2>${weekly?'This week’s moments':'Today’s gentle rhythm'}</h2>${timeline||'<p class="empty-report">Completed moments will appear here automatically.</p>'}</section>`, 'page report-page')}`;
}

function fishingReport(){const r=state.report||state.latestReport,f=r?.facts||{},minutes=Math.max(1,Math.round((f.durationSeconds||((Date.now()-(state.fishing.started||Date.now()))/1000))/60)),memory=f.memory_note||state.summary?.memory_note||'The lake felt peaceful today.',fishNames=f.fishTypes||state.fishing.caughtFish.map(fish=>fish.name);return `${nav()}${shell(`<div class="report-celebration">${sun('celebrating')}<span class="eyebrow">TODAY’S FISHING ADVENTURE</span><h1>Thank you for spending<br>this moment with Sunny.</h1><p class="lead">${escapeHtml(r?.resident||'You shared a peaceful moment by the lake with Sunny today.')}</p></div><div class="warm-report"><article><small>TIME BY THE LAKE</small><b>${minutes} minute${minutes===1?'':'s'}</b><p>A calm little pause in your day.</p></article><article><small>BEAUTIFUL FISH DISCOVERED</small><b>${f.fishCaught??Math.max(1,state.fishing.caught)}</b><p>${escapeHtml(fishNames.length?fishNames.join(' · '):'Each one came to visit at just the right time.')}</p></article><article><small>GENTLE PRACTICE</small><b>${f.tutorialCorrect??state.metrics.tutorialCorrect} movements</b><p>Sunny stayed beside you at every step.</p></article><blockquote><span>${icon('flower')}</span><div><small>A SHARED MEMORY</small><p>“${escapeHtml(memory)}”</p></div></blockquote></div><div class="report-actions">${button('Go fishing again','fishing')}${button('Explore something new','activities','secondary')}${button('Share with family','family','ghost')}</div>`, 'page fishing-report')}`}
function timelineItem(time,title,sub,icon){ return `<div><time>${time}</time><span>${icon}</span><p><b>${title}</b><small>${sub}</small></p></div>`; }

function wellnessPanel(report){const facts=report?.facts;if(!facts)return '';const minutes=Math.max(1,Math.round((facts.durationSeconds||60)/60)),items=[...WELLNESS_DIMENSIONS.fishing];if((facts.conversationTurns||0)>0)items.push(...WELLNESS_DIMENSIONS.conversation);return `<section class="wellness-panel"><span class="eyebrow">HOW TODAY’S MOMENTS HELPED</span><h2>Comfortable ways Mary took part</h2><div>${items.map(item=>`<article><span>${item.icon}</span><p><b>${item.title}</b><small>${item.key==='expression'?(facts.memory_note?`Shared: “${escapeHtml(facts.memory_note)}”`:'Chose to share a memory'):`${minutes} minute${minutes===1?'':'s'} of fishing · ${item.explanation}`}</small></p></article>`).join('')}</div><p class="wellness-note">These are participation notes only, shared without comparison or judgement.</p></section>`}
function family(){const r=state.report||state.latestReport,hasReport=Boolean(r),memory=r?.facts?.memory_note||'No memory was shared today.',highlight=r?.family||'No activity has been recorded yet. When Mary finishes a moment, a gentle factual note will appear here.',interests=state.profile?.interests||[],recent=hasReport?timelineItem('Today','Peaceful fishing',escapeHtml(highlight),'🐟'):'<p class="empty-report">No moments have been recorded yet.</p>';return `${nav()}${shell(`<div class="page-heading compact"><div><span class="eyebrow">FAMILY CIRCLE</span><h1>Good afternoon, Anna.</h1><p>Here’s a warm glimpse of Mum’s day, shared gently and without judgement.</p></div>${button('Call Mary  ♡',null,'secondary','data-toast="Calling is available in the full experience"')}</div>
 <div class="family-grid"><section class="family-main"><div class="report-highlight mini"><div><span class="date">TODAY’S BRIGHT SPOT</span><h2>${hasReport?`“${escapeHtml(memory)}”`:'A gentle space for shared moments'}</h2><p>${escapeHtml(highlight)}</p></div><span class="photo">🌳</span></div><div class="section-head"><h2>Recent moments</h2><button data-go="daily">See full report →</button></div><div class="moment-list">${recent}</div>${wellnessPanel(r)}</section>
 <aside class="family-side"><div>${sun('idle',true)}<h3>Interests Mary has shared</h3><p>Simple facts from moments Mary chose to enjoy — never scores or assessments.</p><div class="interest-facts">${interests.length?interests.slice(0,5).map(item=>`<span>${icon('flower')} ${escapeHtml(item)}</span>`).join(''):'<p class="wellness-empty">No interests have been recorded yet.</p>'}</div></div><div><h3>Next lovely idea</h3><p>Suggestions will grow from the interests Mary chooses to share.</p>${button('Save suggestion',null,'green','data-toast="Suggestion saved"')}</div></aside></div>`, 'page family-page')}`; }

function settings(){ return `${nav()}${shell(`<div class="page-heading">${back()}<span><span class="eyebrow">MAKE MOMENT YOURS</span><h1>Comfort and settings</h1><p>Simple choices to make every moment feel just right.</p></span></div><div class="settings-grid"><section><h2>Experience</h2>${setting('🔊','Sound & spoken guidance','Sunny speaks instructions aloud','sound')}${setting('〰','Gentle motion','Use phone movement in activities','motion')}${setting('Aa','Text size','Currently: Comfortable','text')}</section><section><h2>Connection</h2><button class="setting-row" data-go="pairing"><span>▣</span><p><b>Pair a phone controller</b><small>Connect with a four-digit code</small></p><i>→</i></button><button class="setting-row" data-go="demo"><span>▷</span><p><b>Demo mode</b><small>Explore MOMENT without a controller</small></p><i>→</i></button><button class="setting-row" data-go="error"><span>?</span><p><b>Connection help</b><small>Friendly steps if something is not working</small></p><i>→</i></button></section></div>`, 'page')}`; }
function setting(icon,title,sub,key){ return `<button class="setting-row" data-setting="${key}"><span>${icon}</span><p><b>${title}</b><small>${sub}</small></p><i class="toggle ${state.settings[key]===true?'on':''}"></i></button>`; }

function demo(){ return shell(`<div class="center-state demo-state">${sun('speaking')}<span class="pill">DEMO MODE</span><h1>Explore every MOMENT</h1><p>Choose a screen to preview. Activities work with touch or mouse when a phone is not connected.</p><div class="demo-grid">${['welcome','activities','pairing','fishing','memory','explore','talk','relax','daily','weekly','family','settings','loading','error'].map(v=>button(v[0].toUpperCase()+v.slice(1),v,'secondary')).join('')}</div></div>`, 'state-shell'); }
function loading(){ return shell(`<div class="center-state">${sun('waiting')}<div class="leaf-loader"><i>⌁</i><i>⌁</i><i>⌁</i></div><h1>Preparing a peaceful moment…</h1><p>Sunny is getting everything ready for you.</p></div>`, 'state-shell'); }
function error(){ return shell(`<div class="center-state">${sun('helping')}<span class="pill warm">LET’S TRY THAT AGAIN</span><h1>Your phone took a little pause.</h1><p>Nothing is lost. Make sure both devices are nearby, then reconnect when you’re ready.</p><div class="button-row">${button('Reconnect','pairing')}${button('Not now','settings','ghost')}</div></div>`, 'state-shell'); }

function phone(){
 const f=state.fishing;
 const sensorCapable=window.isSecureContext||['localhost','127.0.0.1'].includes(location.hostname);
 if(state.controllerStep==='connect')return `<main class="phone-shell"><header>${logo()}</header><section class="phone-home">${sun('celebrating')}<span class="eyebrow">CONNECTED SUCCESSFULLY</span><h1>You’re ready to go fishing with Sunny.</h1><p>Your large screen and phone are now together.</p>${button('See how fishing works',null,'primary','data-phone-step="intro"')}</section></main>`;
 if(state.controllerStep==='intro')return `<main class="phone-shell intro-phone"><header>${logo()}<span class="connected"><i></i> With Sunny</span></header><section class="phone-action"><span class="eyebrow">BEFORE WE BEGIN</span><h1>Here’s how we’ll fish together.</h1><div class="phone-intro-list"><div><i>1</i><b>Tap to cast</b><small>Send the line into the lake</small></div><div><i>2</i><b>Lift gently</b><small>When a little fish nibbles</small></div><div><i>3</i><b>Tilt left and right</b><small>Follow our little visitor</small></div><div><i>4</i><b>Turn slowly</b><small>Bring the fish closer</small></div></div><p class="intro-kind">There is no rush. Sunny will be with you.</p>${button('Let’s practise',null,'primary','data-phone-step="ready"')}</section></main>`;
 if(state.controllerStep==='ready')return `<main class="phone-shell"><header>${logo()}<span class="connected"><i></i> Connected</span></header><section class="phone-home">${icon('hand','phone-hand')}<span class="eyebrow">GET COMFORTABLE</span><h1>Hold your phone comfortably.</h1><p>There is no hurry. Use both hands if that feels better.</p>${state.motion.error?`<div class="motion-warning"><b>Motion sensors have not started.</b><span>${state.motion.error}</span></div>`:''}${sensorCapable?button('Allow motion & begin',null,'primary','id="startBtn"'):button('Start visual practice',null,'primary','data-phone-step="tutorial"')}<small class="permission-note">${sensorCapable?'Tap the button once, then choose Allow in Safari.':'This page is HTTP. Open the ngrok HTTPS link to test real motion sensors.'}</small>${motionReadout()}</section></main>`;
 if(state.controllerStep==='tutorial'){const t=tutorialSteps[state.tutorialStep],fb=state.tutorialFeedback;return `<main class="phone-shell practice-phone ${fb?`has-feedback ${fb.kind}`:''}"><header>${logo()}<span class="connected"><i></i> ${state.motion.enabled?'Motion connected':'Visual practice'}</span></header><section class="phone-action">${!state.motion.enabled?'<div class="motion-offline"><b>Phone movement is off on this link.</b><span>Tilting will not respond in Visual practice. Reopen the HTTPS QR link and tap “Allow motion & begin”.</span></div>':''}<span class="eyebrow">PRACTICE ${state.tutorialStep+1} OF 4</span><div class="motion-demo motion-${t.event}"><div class="demo-phone"><span>MOMENT</span></div><i>${fb?.kind==='correct'?'✓':fb?.kind==='wrong'?'↺':t.motion}</i></div><h1>${fb?.kind==='correct'?'Wonderful!':fb?.kind==='wrong'?'Almost — try again':t.title}</h1><p>${fb?.message||(state.motion.enabled?'Move your phone gently — Sunny will notice.':'Follow the picture, then tap the button when it feels comfortable.')}</p>${fb?.kind==='correct'?'<div class="phone-success">Sunny felt the correct movement.</div>':state.motion.enabled?'<div class="sensor-listening"><i></i> Listening for your movement</div>':''}${motionReadout()}${fb?.kind==='correct'?'':button(state.motion.enabled?'Use button instead':'I practised this movement',null,state.motion.enabled?'ghost':'primary',`data-motion="${t.event}"`)}</section></main>`}
 if(state.controllerStep==='complete'){const messages=state.ai.chatMessages.length?state.ai.chatMessages:[{role:'assistant',content:'Did being by the lake bring back a happy memory?'}];return `<main class="phone-shell phone-conversation"><header>${logo()}<span class="connected"><i></i> With Sunny</span></header><section class="phone-action">${sun('speaking')}<span class="eyebrow">A MOMENT WITH SUNNY</span><h1>That was lovely.</h1><div class="chat-thread">${messages.map(m=>`<div class="chat-message ${m.role}">${escapeHtml(m.content)}</div>`).join('')}${state.ai.chatBusy?'<div class="chat-message assistant typing">Sunny is thinking gently…</div>':''}</div><form class="chat-form" data-chat-form><label for="chatInput">Share a memory</label><div><input id="chatInput" name="message" placeholder="Type anything you would like to share"><button class="btn primary" type="submit">Share</button><button class="btn ghost" type="button" data-chat-speech>Speak</button></div></form><div class="chat-choices"><button data-memory="family">It reminded me of family</button><button data-memory="peaceful">I enjoyed the peaceful water</button></div>${state.ai.chatTurns?button('That’s all for now',null,'secondary','data-finish-chat'):''}</section></main>`}
 if(state.controllerStep==='report')return `<main class="phone-shell"><header>${logo()}<span class="connected"><i></i> With Sunny</span></header><section class="phone-home">${sun('celebrating')}<span class="eyebrow">THANK YOU FOR SHARING</span><h1>That was a lovely moment.</h1><p>Your daily memory is ready on the large screen.</p></section></main>`;
 const fish=f.activeFish||FISH_TYPES[0],words={ready:['Tap to cast','A gentle tap sends the line into the lake.','cast'],waiting:['Wait with Sunny','Let’s see who comes to visit us.','wait'],bite:[fish.size==='large'?'Lift with both hands':'Lift your phone gently',fish.size==='large'?'A bigger visitor is here. Chest or shoulder height is enough.':'Something is nibbling on the line!','lift'],biglift:['Hold comfortably','Sunny is helping with the line. Just two quiet seconds.','hold'],left:['Tilt a little left','Follow our visitor comfortably.','left'],right:['Tilt a little right','Lovely — you are doing so well.','right'],reeling:['Turn your phone gently','Slowly bring our visitor closer.','rotate'],caught:['Wonderful!',`You welcomed a ${fish.name}.`,'caught']}[f.stage];
 return `<main class="phone-shell"><header>${logo()}<span class="connected"><i></i> With Sunny</span></header><section class="phone-action"><span class="eyebrow">SUNNY’S PEACEFUL FISHING</span><div class="motion-icon ${f.stage==='biglift'?'holding':''}">${f.stage==='bite'?'↑':f.stage==='biglift'?'••':f.stage==='left'?'←':f.stage==='right'?'→':f.stage==='reeling'?'↻':f.stage==='caught'?icon('spark'):'○'}</div><h1>${words[0]}</h1><p>${words[1]}</p>${f.stage==='caught'?`<div class="phone-catch-actions">${button('Fish again',null,'primary','data-fish-again')}${button('Rest with Sunny',null,'secondary','data-rest-sunny')}</div>`:f.stage!=='waiting'&&f.stage!=='biglift'?button('Done gently',null,'primary',`data-motion="${words[2]}"`):''}<div class="phone-reassure">Never lift above what feels comfortable. Sunny will wait.</div></section></main>`;
}

function modal(title,body){ return `<div class="modal-wrap"><div class="modal">${sun('celebrating')}<span class="eyebrow">A LOVELY MOMENT</span><h1>${title}</h1><p>${body}</p><div class="button-row">${button('Match flowers again',null,'primary','data-restart')}${button('Choose another activity','activities','secondary')}</div></div></div>`; }
function toast(message){ const old=document.querySelector('.toast'); if(old)old.remove(); const el=document.createElement('div'); el.className='toast'; el.textContent=message; document.body.append(el); setTimeout(()=>el.remove(),2600); }

function render(){
 const pages={welcome,activities,fishing,fishingIntro,tutorial,conversation,fishingReport,guidedMoment,momentPlaying,momentComplete,memory,explore:()=>experience('explore'),talk:()=>experience('talk'),relax:()=>experience('relax'),listening,pairing,daily:()=>reports(false),weekly:()=>reports(true),family,settings,demo,loading,error};
 app.innerHTML=state.controller?phone():(pages[state.view]||welcome)();
 if(!state.controller&&state.view==='pairing') preparePairing();
 bindMotionPermissionButton();
 updateMotionReadout();
 speakCurrentMoment();
 window.scrollTo(0,0);
}

function currentSpeech(){
 if(state.controller)return null;
 if(state.view==='welcome')return state.greeting?.personalized?`${state.greeting.greeting} ${state.greeting.suggestion}`:`Hello, ${state.name}. I’m here to keep you company today.`;
 if(state.view==='fishing'){const fish=state.fishing.activeFish||FISH_TYPES[0];return {ready:`Let’s go fishing together, ${state.name}.`,waiting:WAITING_LINES[state.fishing.waitingLine],bite:fish.size==='large'?'A magnificent visitor is nibbling. Lift with both hands, only as high as feels comfortable.':'Oh! Something is nibbling on your line. Lift your phone gently.',biglift:'Lovely and steady. Hold comfortably for two quiet seconds. Sunny is helping with the line.',left:'The fish is swimming to the left. You are doing wonderfully.',right:'Now gently to the right. Perfect, you have got it.',reeling:'Turn slowly and gently. It is almost here!',caught:fish.size==='large'?'Wonderful! You welcomed a magnificent Grand Lake Carp.':fish.name==='Golden Lotus Fish'?'A Golden Lotus Fish! What a very special visitor.':`Wonderful! You welcomed a ${fish.name}.`}[state.fishing.stage]}
 if(state.view==='tutorial'){const feedback=state.tutorialFeedback;if(feedback?.kind==='correct')return 'Perfect! You have got it.';if(feedback?.kind==='wrong')return 'Almost there. Let’s try that movement again.';return tutorialSteps[state.tutorialStep]?.title}
 if(state.view==='conversation')return state.ai.chatMessages.at(-1)?.role==='assistant'?state.ai.chatMessages.at(-1).content:null;
 if(state.view==='momentPlaying'){const type=state.momentSelection?.type;if(type==='explore')return exploreMoments[state.moment.step]?.[1];if(type==='talk')return state.moment.messages.at(-1)?.role==='assistant'?state.moment.messages.at(-1).content:null;if(type==='relax')return state.moment.paused?'Take all the time you need.':'Breathe in comfortably, then let the breath leave slowly.'}
 if(state.view==='momentComplete')return `That was lovely, ${state.name}. Thank you for spending this moment with me.`;
 if(state.view==='fishingReport')return state.report?.resident||'Thank you for spending this lovely moment with Sunny.';return null;
}
function sunnyVoice(){const novelty=/bad news|bells|boing|bubbles|cellos|organ|superstar|trinoids|whisper|wobble|zarvox/i,voices=window.speechSynthesis.getVoices().filter(voice=>/^en[-_]/i.test(voice.lang)&&!novelty.test(voice.name));const score=voice=>(/natural|premium|enhanced/i.test(voice.name)?40:0)+(/samantha|ava|karen|serena|matilda|moira|tessa/i.test(voice.name)?25:0)+(voice.lang==='en-AU'?15:voice.lang==='en-GB'?10:5)+(voice.localService?3:0);return voices.sort((a,b)=>score(b)-score(a))[0]||null}
function speakCurrentMoment(){if(!state.settings.sound||state.controller||!('speechSynthesis'in window))return;const text=currentSpeech();if(!text)return;const voice=sunnyVoice();if(!voice){window.speechSynthesis.onvoiceschanged=()=>{window.speechSynthesis.onvoiceschanged=null;speakCurrentMoment()};return}const key=`${state.view}:${state.fishing.stage}:${state.tutorialStep}:${text}`;if(state.spokenKey===key)return;state.spokenKey=key;window.speechSynthesis.cancel();const naturalText=text.replace(/<br\s*\/?>/gi,'. ').replace(/\s+/g,' ').replace(/\s+([,.!?])/g,'$1').trim();const utterance=new SpeechSynthesisUtterance(naturalText);utterance.rate=.94;utterance.pitch=1;utterance.volume=.82;utterance.lang=voice.lang||'en-AU';utterance.voice=voice;window.speechSynthesis.speak(utterance)}

document.addEventListener('click', e=>{
 const go=e.target.closest('[data-go]'); if(go){ state.previous=state.view; state.view=go.dataset.go; render();if(state.view==='listening')startIntentRecognition(); return; }
 if(e.target.closest('[data-back]')){ state.view=state.previous==='fishing'||state.previous==='memory'?'activities':state.previous; render(); return; }
 if(e.target.closest('[data-controller]')){ state.controller=!state.controller; render(); return; }
 if(e.target.closest('[data-card]')) flipCard(+e.target.closest('[data-card]').dataset.card);
 if(e.target.closest('[data-restart]')){ state.memory={open:[],matched:[],moves:0,hints:1,seconds:0,locked:false}; render(); }
 if(e.target.closest('[data-hint]')) hint();
 if(e.target.closest('[data-cast]'))advanceFishing();
 const phoneStep=e.target.closest('[data-phone-step]');if(phoneStep){state.controllerStep=phoneStep.dataset.phoneStep;if(state.controllerStep==='intro')sendSessionEvent('intro');if(state.controllerStep==='tutorial')sendSessionEvent('start');render();return;}
 if(e.target.closest('[data-retry-pair]')){state.session={id:null,connected:false,error:null,attempts:0};render();return;}
 if(e.target.closest('[data-demo-tutorial]')){state.tutorialStep=0;state.tutorialFeedback=null;state.previous='fishingIntro';state.view='tutorial';render();return;}
 const motion=e.target.closest('[data-motion]');if(motion){sendSessionEvent(motion.dataset.motion);if(state.controllerStep==='tutorial'){showTutorialSuccess()}else if(state.controllerStep==='fishing')advanceFishing();return;}
 const tut=e.target.closest('[data-tutorial]');if(tut){showTutorialSuccess();return;}
 const memoryChoice=e.target.closest('[data-memory]');if(memoryChoice){submitChat(memoryChoice.dataset.memory==='family'?'Being by the lake reminded me of happy times with my family.':'I simply enjoyed the peaceful water today.');return;}
 if(e.target.closest('[data-start-listening]')){startIntentRecognition();return;}
 if(e.target.closest('[data-chat-speech]')){startChatRecognition();return;}
 if(e.target.closest('[data-finish-chat]')){finishConversation();return;}
 if(e.target.closest('[data-fish-again]')){resetForAnotherFish();if(state.controller)sendSessionEvent('fish-again');return;}
 if(e.target.closest('[data-rest-sunny]')){restWithSunny();if(state.controller)sendSessionEvent('rest');return;}
 if(e.target.closest('[data-bait]')){useBait();return;}
 if(e.target.closest('[data-sound]')){state.settings.sound=!state.settings.sound;if(!state.settings.sound&&'speechSynthesis'in window)window.speechSynthesis.cancel();toast(state.settings.sound?'Sunny’s spoken guidance is on':'Spoken guidance is paused');render();return;}
 const t=e.target.closest('[data-toast]'); if(t) toast(t.dataset.toast);
 const story=e.target.closest('[data-story]');if(story){const [type,index]=story.dataset.story.split(':');startMoment(type,index);return;}
 const begin=e.target.closest('[data-begin-moment]');if(begin){state.moment={step:0,started:Date.now(),paused:false,messages:[],busy:false,completed:false,photo:null,photoBusy:false};state.view='momentPlaying';render();return;}
 const momentChoice=e.target.closest('[data-moment-choice]');if(momentChoice){toast(`A lovely choice: ${momentChoice.dataset.momentChoice}`);if(state.moment.step<2){state.moment.step++;render()}else completeMoment();return;}
 const momentPrompt=e.target.closest('[data-moment-prompt]');if(momentPrompt){submitMomentTalk(momentPrompt.dataset.momentPrompt==='family'?'I would like to remember a happy family moment.':'I would like to share something about today.');return;}
 if(e.target.closest('[data-moment-speech]')){startMomentSpeech();return;}
 if(e.target.closest('[data-toggle-pause]')){state.moment.paused=!state.moment.paused;render();return;}
 if(e.target.closest('[data-finish-moment]')){completeMoment();return;}
 const s=e.target.closest('[data-setting]'); if(s){ const k=s.dataset.setting; if(k==='text'){ state.settings.text=state.settings.text==='Comfortable'?'Extra large':'Comfortable'; document.documentElement.classList.toggle('extra-large'); } else{state.settings[k]=!state.settings[k];if(k==='sound'&&!state.settings.sound&&'speechSynthesis'in window)window.speechSynthesis.cancel()} render(); }
});

document.addEventListener('submit',e=>{const momentForm=e.target.closest('[data-moment-chat]');if(momentForm){e.preventDefault();const text=new FormData(momentForm).get('message');if(String(text||'').trim())submitMomentTalk(String(text).trim());return}const form=e.target.closest('[data-chat-form]');if(!form)return;e.preventDefault();const text=new FormData(form).get('message');if(String(text||'').trim())submitChat(String(text).trim());});
document.addEventListener('change',e=>{if(e.target.matches('[data-photo-input]')&&e.target.files?.[0])analysePhoto(e.target.files[0])});

function recognition(onText,onDone,onError){const Recognition=window.SpeechRecognition||window.webkitSpeechRecognition;if(!Recognition){onError('Speech recognition is not available in this browser. You can use the large choices below.');return null}const r=new Recognition();r.lang='en-AU';r.interimResults=true;r.continuous=false;r.onresult=e=>{let text='';for(let i=e.resultIndex;i<e.results.length;i++)text+=e.results[i][0].transcript;onText(text,e.results[e.results.length-1].isFinal)};r.onerror=e=>onError(e.error==='not-allowed'?'Please allow microphone access, or choose an activity below.':'Sunny could not hear that clearly. Please try once more.');r.onend=onDone;return r}
function startIntentRecognition(){state.ai.intentStatus='listening';state.ai.intentError='';state.ai.intentReply='';render();let finalText='';const r=recognition((text,isFinal)=>{state.ai.intentTranscript=text;if(isFinal)finalText=text;render()},()=>{if(finalText)requestIntent(finalText);else if(state.ai.intentStatus==='listening'){state.ai.intentStatus='idle';render()}},message=>{state.ai.intentStatus='error';state.ai.intentError=message;render()});if(r)try{r.start()}catch{state.ai.intentStatus='idle';render()}}
async function requestIntent(transcript){state.ai.intentStatus='thinking';render();try{const response=await fetch(`${API_BASE}/api/ai/intent`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({transcript})});if(!response.ok)throw new Error();const data=await response.json();state.ai.intentReply=data.reply||'That sounds lovely.';state.ai.intentStatus='done';render();const destination={fishing:'pairing',explore:'explore',talk:'talk',relax:'relax'}[data.intent];if(destination)setTimeout(()=>{state.previous='listening';state.view=destination;render()},1400);else state.ai.intentError='I am not quite sure yet. Try saying fishing, explore, talk, or relax.'}catch{state.ai.intentStatus='error';state.ai.intentError='Sunny could not connect just now. Please choose one of the gentle options below.';render()}}

async function submitChat(text){if(state.ai.chatBusy)return;if(!state.ai.chatMessages.length)state.ai.chatMessages.push({role:'assistant',content:'Did being by the lake bring back a happy memory?'});state.ai.chatMessages.push({role:'user',content:text});state.ai.chatBusy=true;render();try{const response=await fetch(`${API_BASE}/api/ai/chat`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({sessionId:state.session.id,message:text})});if(!response.ok)throw new Error();const data=await response.json();state.ai.chatMessages.push({role:'assistant',content:data.reply});state.ai.chatTurns=data.turns||state.ai.chatTurns+1}catch{state.ai.chatMessages.push({role:'assistant',content:'Thank you for sharing that with me. I’m glad we could enjoy this moment together.'});state.ai.chatTurns++}state.ai.chatBusy=false;if(state.controller)sendSessionEvent('chat');render()}
async function submitMomentTalk(text){const m=state.moment;if(m.busy)return;if(!m.messages.length)m.messages.push({role:'assistant',content:`I’m right here, ${state.name}. What would you like to share?`});m.messages.push({role:'user',content:text});m.busy=true;render();try{const item=experiences[state.momentSelection.type].cards[state.momentSelection.index],response=await fetch(`${API_BASE}/api/ai/companion`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({message:text,messages:m.messages,activity:state.momentSelection.type,topic:item[1]})});if(!response.ok)throw new Error();const data=await response.json();m.messages.push({role:'assistant',content:data.reply})}catch{m.messages.push({role:'assistant',content:'Thank you for sharing that with me. I’m happy to sit with this memory beside you.'})}m.busy=false;render()}
async function analysePhoto(file){const m=state.moment;if(m.photoBusy)return;if(file.size>2_500_000){toast('Please choose a photo smaller than 2.5 MB.');return}m.photoBusy=true;try{const image=await new Promise((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=reject;reader.readAsDataURL(file)});m.photo=String(image);render();const response=await fetch(`${API_BASE}/api/ai/photo`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({image:m.photo,context:'Invite the person to tell the story, without identifying anyone.'})});if(!response.ok)throw new Error();const data=await response.json();m.messages.push({role:'assistant',content:data.reply})}catch{m.messages.push({role:'assistant',content:'This looks like a meaningful photograph. What would you like to tell me about the moment it holds?'})}m.photoBusy=false;render()}
function startChatRecognition(){let finalText='';const r=recognition((text,isFinal)=>{if(isFinal)finalText=text},()=>{if(finalText)submitChat(finalText)},message=>toast(message));if(r)try{r.start();toast('Sunny is listening…')}catch{toast('Please try the Speak button again.')}}
function startMomentSpeech(){let finalText='';const r=recognition((text,isFinal)=>{if(isFinal)finalText=text},()=>{if(finalText)submitMomentTalk(finalText)},message=>toast(message));if(r)try{r.start();toast('Sunny is listening…')}catch{toast('Please try the Speak button again.')}}
async function finishConversation(){
 if(state.ai.chatBusy)return;state.ai.chatBusy=true;render();
 const endedAt=new Date().toISOString(),startedAt=new Date(state.fishing.started||Date.now()-60000).toISOString();
 const metrics={startedAt,endedAt,durationSeconds:Math.max(1,Math.round((Date.parse(endedAt)-Date.parse(startedAt))/1000)),fishCaught:state.fishing.caught,fishTypes:state.fishing.caughtFish.map(fish=>fish.name),tutorialCorrect:state.metrics.tutorialCorrect,tutorialWrong:state.metrics.tutorialWrong};
 try{
  if(state.session.id)await fetch(`${API_BASE}/api/session/${state.session.id}/metrics`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify(metrics)});
  const summaryResponse=await fetch(`${API_BASE}/api/ai/summary`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({sessionId:state.session.id})});if(summaryResponse.ok)state.summary=await summaryResponse.json();
  const reportResponse=await fetch(`${API_BASE}/api/ai/report`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({sessionId:state.session.id})});if(!reportResponse.ok)throw new Error();state.report=await reportResponse.json();
 }catch{state.summary=state.summary||{memory_note:state.ai.chatMessages.find(m=>m.role==='user')?.content||'The lake felt peaceful today.'};state.report={resident:`You spent ${Math.max(1,Math.round(metrics.durationSeconds/60))} lovely minute${metrics.durationSeconds>=90?'s':''} by the lake today. Thank you for sharing this moment with Sunny.`,family:'Mary enjoyed a peaceful fishing moment with Sunny today.',facts:{...metrics,memory_note:state.summary.memory_note}}}
 state.ai.chatBusy=false;if(state.controller){state.controllerStep='report';sendSessionEvent('report')}else state.view='fishingReport';render();
}

function flipCard(i){ const m=state.memory;if(m.locked||m.open.includes(i)||m.matched.includes(i))return;m.open.push(i);render();if(m.open.length===2){m.moves++;m.locked=true;setTimeout(()=>{const[a,b]=m.open;if(flowers[a][0]===flowers[b][0])m.matched.push(a,b);m.open=[];m.locked=false;render();if(m.matched.length===flowers.length)setTimeout(()=>{app.insertAdjacentHTML('beforeend',modal('Wonderful work, Mary!','You found every flower pair. Take a moment to enjoy what you did.'));},300);},750);}}
function hint(){ const m=state.memory;if(!m.hints)return;const first=flowers.findIndex((f,i)=>!m.matched.includes(i));const second=flowers.findIndex((f,i)=>i!==first&&!m.matched.includes(i)&&f[0]===flowers[first][0]);m.hints--;m.open=[first,second];m.locked=true;render();setTimeout(()=>{m.open=[];m.locked=false;render();},1200);}
let biteTimer=null,bigLiftTimer=null,lastLocalEvent=null,outgoingEventSeq=0,lastSessionEventSeq=0;
function chooseFish(){const grand=FISH_TYPES.find(fish=>fish.size==='large');if(state.fishing.caught>=2&&grand)return grand;const multiplier=state.fishing.baitActive?2:1,weights=FISH_TYPES.map((fish,index)=>fish.rarity*(index?multiplier:1)),total=weights.reduce((a,b)=>a+b,0);let roll=Math.random()*total;for(let i=0;i<weights.length;i++){roll-=weights[i];if(roll<=0)return FISH_TYPES[i]}return FISH_TYPES[0]}
function makeStruggle(fish){const steps=fish.rarity<=.1?4:fish.rarity<=.22?3:2;return Array.from({length:steps},()=>Math.random()<.5?'left':'right')}
function scheduleBite(){clearTimeout(biteTimer);const f=state.fishing,delay=(2500+Math.random()*4500)*(f.baitActive ? 0.5 : 1);f.lastBiteDelay=Math.round(delay);biteTimer=setTimeout(()=>{if(f.stage!=='waiting')return;f.stage='bite';f.baitActive=false;sendSessionEvent('stage:bite');render()},delay)}
function beginGrandHold(){clearTimeout(bigLiftTimer);const f=state.fishing;f.stage='biglift';f.progress=18;render();bigLiftTimer=setTimeout(()=>{if(f.stage!=='biglift')return;f.struggleStep=0;f.stage=f.struggle[0]||'left';f.progress=25;sendSessionEvent('stage:grand-ready');render()},2000)}
function advanceFishing(){const f=state.fishing;if(f.stage==='ready'){if(!f.started)f.started=Date.now();f.round++;f.stage='waiting';f.progress=0;f.waitingLine=Math.floor(Math.random()*WAITING_LINES.length);if(!state.controller){f.activeFish=chooseFish();f.struggle=makeStruggle(f.activeFish);f.struggleStep=0;sendSessionEvent(`plan:${FISH_TYPES.indexOf(f.activeFish)}:${f.struggle.join(',')}:${f.waitingLine}`);scheduleBite()}render()}else if(f.stage==='bite'){if(f.activeFish?.size==='large'){beginGrandHold();return}f.struggleStep=0;f.stage=f.struggle[0]||'left';render()}else if(f.stage==='left'||f.stage==='right'){f.struggleStep++;f.stage=f.struggle[f.struggleStep]||'reeling';if(f.stage==='reeling')f.progress=30;render()}else if(f.stage==='reeling'){f.progress+=35;if(f.progress>=100){f.progress=100;f.stage='caught';f.caught++;f.caughtFish.push(f.activeFish||FISH_TYPES[0])}render()}}
function resetForAnotherFish(){clearTimeout(biteTimer);clearTimeout(bigLiftTimer);const f=state.fishing;f.stage='ready';f.activeFish=null;f.struggle=[];f.struggleStep=0;f.progress=0;f.baitActive=false;render()}
function restWithSunny(){clearTimeout(biteTimer);clearTimeout(bigLiftTimer);if(!state.ai.chatMessages.length)state.ai.chatMessages=[{role:'assistant',content:'Did being by the lake bring back a happy memory?'}];if(state.controller)state.controllerStep='complete';else state.view='conversation';render()}
function useBait(){const f=state.fishing;if(!f.bait||f.baitActive)return;f.bait--;f.baitActive=true;toast('Bait is ready — a little visitor may arrive sooner.');if(f.stage==='waiting'&&!state.controller){f.activeFish=chooseFish();f.struggle=makeStruggle(f.activeFish);f.struggleStep=0;sendSessionEvent(`plan:${FISH_TYPES.indexOf(f.activeFish)}:${f.struggle.join(',')}:${f.waitingLine}`);scheduleBite()}render()}

function advanceTutorial(){state.tutorialFeedback=null;if(state.tutorialStep<3){state.tutorialStep++;render()}else{state.tutorialStep=0;state.fishing.stage='ready';if(state.controller)state.controllerStep='fishing';else state.view='fishing';render()}}
function showTutorialSuccess(){if(state.tutorialFeedback?.kind==='correct')return;state.metrics.tutorialCorrect++;state.tutorialFeedback={kind:'correct',message:'That was the correct movement. Moving to the next step…'};render();setTimeout(advanceTutorial,1050)}
function showTutorialWrong(detected){state.metrics.tutorialWrong++;state.tutorialFeedback={kind:'wrong',message:`Try ${tutorialSteps[state.tutorialStep].title.toLowerCase()}. Keep the movement small and comfortable.`};render();setTimeout(()=>{if(state.tutorialFeedback?.kind==='wrong'){state.tutorialFeedback=null;render()}},1800)}
async function sendSessionEvent(event){if(!state.session.id)return;lastLocalEvent=event;outgoingEventSeq++;try{await fetch(`${API_BASE}/api/session/${state.session.id}/event`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({event,seq:outgoingEventSeq,role:state.controller?'controller':'display'})})}catch{}}
async function preparePairing(){
 if(state.session.error)return;
 if(!state.session.id){try{const r=await fetch(`${API_BASE}/api/session`,{method:'POST'});if(!r.ok)throw new Error();state.session={...await r.json(),connected:false,error:null,attempts:0};render();return}catch{state.session.attempts=(state.session.attempts||0)+1;if(state.session.attempts<3){setTimeout(preparePairing,700);return}state.session.error=location.hostname.endsWith('github.io')?'GitHub Pages can show the experience, but it cannot create a live phone session.':'The connection paused for a moment. Please try once more to create a fresh QR code.';render();return}}
 const qr=document.querySelector('#qr');if(qr&&!qr.children.length&&window.qrcode){const code=qrcode(0,'M');code.addData(qr.dataset.url);code.make();qr.innerHTML=code.createSvgTag({cellSize:5,margin:2,scalable:true})}
}
let lastSessionUpdate=0;
setInterval(async()=>{if(!state.session.id)return;try{const role=state.controller?'controller':'display',r=await fetch(`${API_BASE}/api/session/${state.session.id}?role=${role}`);if(!r.ok)return;const s=await r.json();if(!state.controller&&s.connected!==state.session.connected){state.session.connected=s.connected;if(!s.connected&&state.view!=='pairing')toast('The phone connection is resting. Reopen the controller and MOMENT will reconnect.');render()}const serverChat=JSON.stringify(s.chatMessages||[]),localChat=JSON.stringify(state.ai.chatMessages||[]);if(!state.ai.chatBusy&&serverChat!==localChat&&(state.view==='conversation'||state.controllerStep==='complete')){state.ai.chatMessages=s.chatMessages;state.ai.chatTurns=s.chatTurns||0;render()}if((s.eventSeq||0)>lastSessionEventSeq&&s.event){lastSessionEventSeq=s.eventSeq;lastSessionUpdate=s.updated||lastSessionUpdate;if(s.event===lastLocalEvent)lastLocalEvent=null;else handleRemote(s.event)}}catch{}},500);
setInterval(()=>{if(state.view==='memory'&&state.memory.matched.length<flowers.length&&!state.memory.locked){state.memory.seconds++;const time=document.querySelector('.stat-row>div:nth-child(2) b');if(time)time.textContent=formatTime(state.memory.seconds)}},1000);
function handleRemote(event){
 const f=state.fishing;
 if(event.startsWith('plan:')){const [,fishIndex,sequence,line]=event.split(':');f.activeFish=FISH_TYPES[+fishIndex]||FISH_TYPES[0];f.struggle=sequence?sequence.split(','):['left','right'];f.struggleStep=0;f.waitingLine=+line||0;if(state.controller)f.stage='waiting';render();return}
 if(event==='stage:bite'&&state.controller){f.stage='bite';f.baitActive=false;render();return}
 if(event==='stage:grand-ready'){if(f.stage==='biglift'){clearTimeout(bigLiftTimer);f.struggleStep=0;f.stage=f.struggle[0]||'left';f.progress=25;render()}return}
 if(event==='fish-again'){if((state.controller&&state.controllerStep==='fishing')||(!state.controller&&state.view==='fishing'))resetForAnotherFish();return}
 if(event==='rest'){if((state.controller&&state.controllerStep==='fishing')||(!state.controller&&state.view==='fishing'))restWithSunny();return}
 if(event==='intro'){state.view='fishingIntro';render();return}if(event==='start'){state.view='tutorial';state.tutorialStep=0;state.tutorialFeedback=null;render();return}
 if(event==='chat'&&state.view==='conversation'){render();return}if(event==='report'){fetch(`${API_BASE}/api/session/${state.session.id}`).then(r=>r.json()).then(s=>{state.report=s.report;state.view='fishingReport';render()}).catch(()=>{});return}
 if(state.view==='tutorial'&&event.startsWith('wrong:')){showTutorialWrong(event.split(':')[1]);return}if(state.view==='tutorial'&&tutorialSteps[state.tutorialStep]?.event===event){showTutorialSuccess();return}
 if((state.view==='fishing'||state.controllerStep==='fishing')&&event!=='wait')advanceFishing();
}
if(state.controller&&state.session.id){fetch(`${API_BASE}/api/session/${state.session.id}/connect`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({role:'controller'})}).catch(()=>{});}

function motionReadout(){return `<section class="motion-readout" aria-live="polite"><header><b>Live motion data</b><span id="motionStatus">${state.motion.enabled?'Receiving sensor data':'Waiting to start'}</span></header><div><label>X <strong id="motionX">0.00</strong></label><label>Y <strong id="motionY">0.00</strong></label><label>Z <strong id="motionZ">0.00</strong></label></div>${DEBUG?'<div class="debug-motion"><label>Beta <strong id="motionBeta">0.0</strong></label><label>Gamma <strong id="motionGamma">0.0</strong></label><label>Turn <strong id="motionAlpha">0.0</strong></label><label>Detected <strong id="motionDetected">—</strong></label></div>':''}</section>`}
function updateMotionReadout(values){
 if(values)state.motion.values=values;
 const v=state.motion.values||{x:0,y:0,z:0};
 const x=document.getElementById('motionX'),y=document.getElementById('motionY'),z=document.getElementById('motionZ'),status=document.getElementById('motionStatus');
 if(x)x.textContent=Number(v.x||0).toFixed(2);if(y)y.textContent=Number(v.y||0).toFixed(2);if(z)z.textContent=Number(v.z||0).toFixed(2);if(status)status.textContent=state.motion.enabled?'Receiving sensor data':'Waiting to start';
 const o=state.motion.orientation||{};[['motionBeta',o.beta],['motionGamma',o.gamma],['motionAlpha',o.alphaDelta],['motionDetected',o.detected||'—']].forEach(([id,value])=>{const el=document.getElementById(id);if(el)el.textContent=typeof value==='number'?value.toFixed(1):value});
}
function bindMotionPermissionButton(){
 const startBtn=document.getElementById('startBtn');
 if(startBtn)startBtn.onclick=requestMotionPermission;
}
async function requestMotionPermission(){
 try{
  if(!window.isSecureContext&&!['localhost','127.0.0.1'].includes(location.hostname))throw new Error('iPhone motion sensors require a secure HTTPS link. The current local HTTP address can only use the button fallback.');
  // Both permission calls are created immediately inside this direct button-click handler.
  const requests=[];
  if(typeof DeviceMotionEvent!=='undefined'&&typeof DeviceMotionEvent.requestPermission==='function')requests.push(DeviceMotionEvent.requestPermission());
  if(typeof DeviceOrientationEvent!=='undefined'&&typeof DeviceOrientationEvent.requestPermission==='function')requests.push(DeviceOrientationEvent.requestPermission());
  const results=await Promise.all(requests);
  if(results.some(result=>result!=='granted'))throw new Error('Please choose Allow when Safari asks for Motion & Orientation access.');
  startListening();
  state.controllerStep='tutorial';sendSessionEvent('start');render();
 }catch(err){state.motion.error=err.message||'Motion access could not be enabled.';state.motion.permission='denied';render()}
}
function startListening(){
  state.motion.enabled=true;state.motion.permission='granted';state.motion.error=null;state.motion.baseline=null;state.motion.samples=0;
  window.removeEventListener('deviceorientation',onOrientation);
  window.removeEventListener('devicemotion',onMotion);
  window.addEventListener('deviceorientation',onOrientation,{passive:true});
  window.addEventListener('devicemotion',onMotion,{passive:true});
  setTimeout(()=>{if(state.motion.enabled&&state.motion.samples===0){state.motion.enabled=false;state.motion.error='Safari allowed the request, but no movement data arrived. In Settings → Safari, turn on Motion & Orientation Access, then reopen the HTTPS QR link.';state.controllerStep='ready';render()}},3000);
}
function onOrientation(e){
 if(!state.motion.enabled||e.beta==null||e.gamma==null)return;
 state.motion.samples++;
 if(!state.motion.baseline){state.motion.baseline={beta:e.beta,gamma:e.gamma,alpha:e.alpha||0};return}
 const now=Date.now();if(now-state.motion.lastEvent<1100)return;
 const b=e.beta-state.motion.baseline.beta,g=e.gamma-state.motion.baseline.gamma,a=Math.abs((e.alpha||0)-state.motion.baseline.alpha);
 const expected=expectedMotion();let detected=null;
 const alphaDelta=Math.min(a,360-a);
 if(alphaDelta>THRESHOLDS.rotateAlpha)detected='rotate';
 else if(g<THRESHOLDS.tiltLeftGamma)detected='left';
 else if(g>THRESHOLDS.tiltRightGamma)detected='right';
 else if(b<THRESHOLDS.liftBetaNegative||b>THRESHOLDS.liftBetaPositive)detected='lift';
 state.motion.orientation={beta:b,gamma:g,alphaDelta,detected};updateMotionReadout();
 if(detected===expected)acceptMotion(detected,e);else if(detected&&(state.controllerStep==='tutorial'||state.controllerStep==='fishing'))rejectMotion(detected,e);
}
function onMotion(e){const a=e.accelerationIncludingGravity;if(!a)return;state.motion.samples++;updateMotionReadout({x:a.x,y:a.y,z:a.z});if(Date.now()-state.motion.lastEvent<1100)return;if(expectedMotion()==='lift'&&Math.abs(a.z||0)>THRESHOLDS.liftAccelerationZ)acceptMotion('lift')}
function expectedMotion(){if(state.controllerStep==='tutorial')return tutorialSteps[state.tutorialStep]?.event;if(state.controllerStep==='fishing')return {bite:'lift',left:'left',right:'right',reeling:'rotate'}[state.fishing.stage];return null}
function acceptMotion(event,e){
 state.motion.lastEvent=Date.now();if(e)state.motion.baseline={beta:e.beta,gamma:e.gamma,alpha:e.alpha||0};
 if(navigator.vibrate)navigator.vibrate(80);sendSessionEvent(event);toast('Wonderful — Sunny felt that movement!');
 if(state.controllerStep==='tutorial')showTutorialSuccess();else if(state.controllerStep==='fishing')advanceFishing();
}
function rejectMotion(event,e){state.motion.lastEvent=Date.now();if(e)state.motion.baseline={beta:e.beta,gamma:e.gamma,alpha:e.alpha||0};if(navigator.vibrate)navigator.vibrate([40,50,40]);sendSessionEvent(`wrong:${event}`);if(state.controllerStep==='tutorial')showTutorialWrong(event);else toast(`Almost — ${currentFishingPrompt()} gently. Sunny will wait for you.`)}
function currentFishingPrompt(){return{bite:'lift your phone',left:'tilt a little left',right:'tilt a little right',reeling:'turn your phone'}[state.fishing.stage]||'try that movement again'}

async function loadLatest(){try{const [latestResponse,greetingResponse]=await Promise.all([fetch(`${API_BASE}/api/ai/latest`),fetch(`${API_BASE}/api/ai/greeting`)]);if(latestResponse.ok){const data=await latestResponse.json();state.profile=data.profile;state.latestReport=data.report}if(greetingResponse.ok)state.greeting=await greetingResponse.json();if(state.view==='welcome')render()}catch{}}
render();loadLatest();
